int send_count;
int* send_buffer = NULL;
int* recv_buffer = NULL;
int* recv_counts = NULL;
int* displs = NULL;
MPI_Request request;
int err;

// Obtém o rank e o tamanho do comunicador global
err = MPI_Comm_rank(MPI_COMM_WORLD, &rank);
err = MPI_Comm_size(MPI_COMM_WORLD, &size);

// Cada processo envia uma quantidade diferente de dados (ex: rank + 1 inteiros)
send_count = rank + 1;
send_buffer = (int*)malloc(send_count * sizeof(int));
for (int i = 0; i < send_count; ++i) {
    send_buffer[i] = rank * 10 + i;
}

