displs = (int*)malloc(size * sizeof(int));

int total_recv_elements = 0;
for (int i = 0; i < size; ++i) {
    recv_counts[i] = i + 1; // Processo i enviará i+1 elementos
    displs[i] = total_recv_elements;
    total_recv_elements += recv_counts[i];
}

// Aloca o buffer de recepção com o tamanho total necessário
recv_buffer = (int*)malloc(total_recv_elements * sizeof(int));

// Inicializa a requisição persistente para Allgatherv
