int rank, size;
char* send_buffer = NULL;
char* recv_buffer = NULL;
int* send_counts = NULL;
MPI_Aint* sdispls = NULL; // MPI_Aint para deslocamentos em bytes
MPI_Datatype* send_types = NULL;
int* recv_counts = NULL;
MPI_Aint* rdispls = NULL;
MPI_Datatype* recv_types = NULL;
MPI_Request request;
int err;

// Obtém o rank e o tamanho do comunicador global
err = MPI_Comm_rank(MPI_COMM_WORLD, &rank);
err = MPI_Comm_size(MPI_COMM_WORLD, &size);

// Aloca arrays para counts, displs e types
send_counts = (int*)malloc(size * sizeof(int));
sdispls = (MPI_Aint*)malloc(size * sizeof(MPI_Aint));
send_types = (MPI_Datatype*)malloc(size * sizeof(MPI_Datatype));
recv_counts = (int*)malloc(size * sizeof(int));
rdispls = (MPI_Aint*)malloc(size * sizeof(MPI_Aint));
recv_types = (MPI_Datatype*)malloc(size * sizeof(MPI_Datatype));

int total_send_bytes = 0;
int total_recv_bytes = 0;

// Define e calcula para Alltoallw
for (int i = 0; i < size; ++i) {
    // Exemplo: Processo 'rank' envia 1 int para 'i' e 1 char para 'i+1 (mod size)'
    // Para simplificar, faremos cada processo enviar e receber um INT para todos.
    // Mas demonstraremos o uso de diferentes datatypes nos arrays.
    send_counts[i] = 1; // Envia 1 elemento para cada processo
    recv_counts[i] = 1; // Recebe 1 elemento de cada processo

    send_types[i] = (i % 2 == 0) ? MPI_INT : MPI_CHAR;
    recv_types[i] = (i % 2 == 0) ? MPI_INT : MPI_CHAR;

    int send_type_size;
    MPI_Type_size(send_types[i], &send_type_size);
    sdispls[i] = total_send_bytes;
    total_send_bytes += send_counts[i] * send_type_size;

    int recv_type_size;
    MPI_Type_size(recv_types[i], &recv_type_size);
    rdispls[i] = total_recv_bytes;
    total_recv_bytes += recv_counts[i] * recv_type_size;
}

// Aloca e inicializa o buffer de envio (genérico para char para flexibilidade de tipos)
send_buffer = (char*)malloc(total_send_bytes);
// Preenche com dados de exemplo
char* current_send_ptr = send_buffer;
for (int i = 0; i < size; ++i) {
    if (send_types[i] == MPI_INT) {
        *((int*)current_send_ptr) = rank * 10 + i; // Valor int
        current_send_ptr += sizeof(int);
    } else if (send_types[i] == MPI_CHAR) {
        *((char*)current_send_ptr) = 'A' + rank + i;
        current_send_ptr += sizeof(char);
    }
}

// Aloca o buffer de recepção
recv_buffer = (char*)malloc(total_recv_bytes);

// Inicializa a requisição persistente para Alltoallw
err = MPIX_Alltoallw_init(send_buffer, send_counts, sdispls, send_types,
                            recv_buffer, recv_counts, rdispls, recv_types,
                            MPI_COMM_WORLD, MPI_INFO_NULL, &request);

if (err == MPI_SUCCESS) {
    // Inicia a operação coletiva Alltoallw persistente
    err = MPI_Start(&request);
    if (err == MPI_SUCCESS) {
        // Espera a conclusão da operação
        MPI_Status status;
        err = MPI_Wait(&request, &status);

        if (err == MPI_SUCCESS) {
            // Os dados trocados estão agora em recv_buffer
            // printf("Processo %d recebeu: ", rank);
