err = MPI_Comm_size(MPI_COMM_WORLD, &size);

// Cada processo tem um valor a contribuir para o exscan
my_value = rank + 1; // Ex: P0=1, P1=2, P2=3, ...

// Inicializa a requisição persistente para Exscan
// Usaremos a operação MPI_SUM para acumular os valores
err = MPIX_Exscan_init(&my_value, &exclusive_prefix_sum, count, MPI_INT, MPI_SUM, MPI_COMM_WORLD, MPI_INFO_NULL, &request);

