// Declarações
int rank, size;
int count = 5;
int sendbuf[5] = {1, 2, 3, 4, 5};
int recvbuf[20];
int recvcounts[4] = {5, 5, 5, 5};
int displs[4] = {0, 5, 10, 15};
MPI_Request request;
MPI_Comm comm = MPI_COMM_WORLD;

MPI_Comm_rank(comm, &rank);
MPI_Comm_size(comm, &size);

// Inicializa a operação persistente
int err = MPIX_Gatherv_init(sendbuf, count, MPI_INT, recvbuf, recvcounts, displs, MPI_INT, 0, comm, MPI_INFO_NULL, &request);

if (err == MPI_SUCCESS) {
    // Executa a operação 10 vezes de forma persistente
