// Declarações
int halo_data[1] = {10};
int ghost_cells[4]; // Supondo 4 vizinhos
MPI_Request request;
MPI_Comm cart_comm;
int dims[1] = {4}, periods[1] = {1};

// Cria topologia cartesiana
MPI_Cart_create(MPI_COMM_WORLD, 1, dims, periods, 0, &cart_comm);

// Inicializa a operação persistente de vizinhança
int err = MPIX_Neighbor_allgather_init(halo_data, 1, MPI_INT, ghost_cells, 1, MPI_INT, cart_comm, MPI_INFO_NULL, &request);

if (err == MPI_SUCCESS) {
    // Ciclo de atualização halo
    for (int i = 0; i < 5; i++) {
        MPI_Start(&request);
        MPI_Wait(&request, MPI_STATUS_IGNORE);
    }
}

MPI_Request_free(&request);
MPI_Comm_free(&cart_comm);

