MPI_Win win = MPI_WIN_NULL;
int err = MPI_SUCCESS;
MPI_Info info = MPI_INFO_NULL;

// Variáveis para a operação MPI_Accumulate
int local_value; // Buffer de origem no processo chamador
int origin_count = 1;
MPI_Datatype origin_datatype = MPI_INT;
int target_rank = 0; // Rank alvo para a operação (ex: processo raiz)
MPI_Aint target_disp = 0; // Deslocamento no buffer da janela do alvo
int target_count = 1;
MPI_Datatype target_datatype = MPI_INT;
MPI_Op op = MPI_SUM; // Operação de redução (ex: soma)

// Buffer que será exposto na janela (apenas no processo alvo)
int *win_buffer = NULL;
MPI_Aint winsize; // Tamanho da janela
int windisp_unit; // Unidade de deslocamento da janela

// Alocação e inicialização do buffer da janela para o processo alvo (rank 0 neste exemplo)
if (rank == target_rank) {
    winsize = sizeof(int); // A janela exporá um único inteiro
    win_buffer = (int *)malloc(winsize);
    if (win_buffer == NULL) {
        err = MPI_ERR_OTHER; // Erro de alocação
    } else {
        *win_buffer = 0; // Inicializa o valor na janela
        windisp_unit = sizeof(int); // A unidade de deslocamento é o tamanho de um int
    }
} else {
    winsize = 0; // Outros processos não expõem janela
    win_buffer = NULL;
    windisp_unit = 1; // Define uma unidade padrão, embora irrelevante para janela de tamanho 0
}

if (err != MPI_ERR_OTHER) { // Se não houve erro de alocação inicial
    // Cria uma janela MPI para acesso remoto à memória (RMA)
    err = MPI_Win_create(win_buffer, winsize, windisp_unit, info, comm, &win);
}


if (err == MPI_SUCCESS) {
    // Inicializa o valor local do processo
    local_value = rank + 10; // Cada processo tem um valor diferente

    // Inicia um epoch de acesso RMA com MPI_Win_fence para sincronizar todos os processos.
    err = MPI_Win_fence(0, win);

    if (err == MPI_SUCCESS) {
        // Somente processos que não são o alvo realizam a operação de acumulação
        if (rank != target_rank) {
            // Realiza a operação de acumulação: local_value é adicionado a win_buffer no target_rank
            err = MPI_Accumulate(&local_value, origin_count, origin_datatype,
                                 target_rank, target_disp, target_count, target_datatype,
                                 op, win);

            if (err != MPI_SUCCESS) {
                // Tratamento de erro para MPI_Accumulate
            }
        }
    } else {
        // Tratamento de erro para MPI_Win_fence
    }

    // Termina o epoch de acesso RMA com outro MPI_Win_fence para garantir que todas as operações RMA sejam concluídas
    int fence_err = MPI_Win_fence(0, win);
    if (fence_err != MPI_SUCCESS) {
        // Tratamento de erro para o segundo MPI_Win_fence
        if (err == MPI_SUCCESS) err = fence_err; // Propaga erro se nenhum outro erro ocorreu
    }

    // No processo alvo, o resultado da acumulação pode ser lido após o fence
    if (rank == target_rank && win_buffer != NULL) {
        // printf("Processo %d: Valor acumulado na janela = %d\n", rank, *win_buffer); // Lógica de aplicação com o valor acumulado
    }
} else {
    // Tratamento de erro para MPI_Win_create ou alocação inicial
}

// Libera os recursos da janela MPI
if (win != MPI_WIN_NULL) { // Verifica se a janela foi criada
    int free_err = MPI_Win_free(&win);
    if (free_err != MPI_SUCCESS) {
        // Tratamento de erro para MPI_Win_free
    }
}

// Libera a memória alocada para o buffer da janela
if (rank == target_rank && win_buffer != NULL) {
    free(win_buffer);
}

