    *(int*)attribute_val_out = *(int*)attribute_val_in;
    *flag_out = 1;
    return MPI_SUCCESS;
}

int attribute_delete_callback(MPI_Comm oldcomm, int keyval_arg, void *attribute_val, void *extra_state) {
    // Não há nada para liberar neste exemplo, já que 'attribute_value' é uma variável local.
    return MPI_SUCCESS;
}

// Cria uma nova chave de atributo
err = MPI_Keyval_create(attribute_copy_callback, attribute_delete_callback, &keyval, NULL);

if (err == MPI_SUCCESS) {
    // Associa o valor 'stored_value' ao comunicador usando a chave 'keyval'.
    // O terceiro argumento é um ponteiro para o valor do atributo.
    err = MPI_Attr_put(comm, keyval, &stored_value);

    if (err == MPI_SUCCESS) {
        // Tenta recuperar o valor do atributo associado à chave 'keyval' no comunicador 'comm'.
        // O terceiro argumento é um ponteiro para a variável que receberá o valor.
        // O quarto argumento é um ponteiro para a flag que indicará se o atributo foi encontrado.
        err = MPI_Attr_get(comm, keyval, &retrieved_value, &flag);

        if (err == MPI_SUCCESS) {
            // Verifica se o atributo foi encontrado
            if (flag) {
                // Sucesso: atributo encontrado e recuperado em 'retrieved_value'.
                // (Em um programa real, poderíamos imprimir 'retrieved_value' ou usá-lo).
            } else {
                // O atributo não foi encontrado, o que não deve acontecer neste fluxo de exemplo.
                // fprintf(stderr, "Erro: Atributo com keyval %d não encontrado.\n", keyval);
            }
        }
    }
}

// Limpeza: Libera a chave do atributo criada.
if (keyval != MPI_KEYVAL_INVALID) {
    err = MPI_Keyval_free(&keyval);
    if (err != MPI_SUCCESS) {
        // Tratamento de erro
        // fprintf(stderr, "Erro ao liberar keyval do atributo.\n");
    }
}

// Declarações
// NOTA: MPI_Attr_put é uma função legada e não é mais recomendada. Para desenvolvimento moderno, utilize MPI_Comm_set_attr e MPI_Comm_get_attr.
// As funções de cópia e exclusão de atributos (MPI_Copy_function e MPI_Delete_function) para MPI_Attr_put devem ser definidas de acordo com a documentação do MPI-1.0.
// Para simplicidade e compatibilidade (apesar da depreciação), usaremos funções NULL para o exemplo.
MPI_Comm comm_attr_test;
int keyval_attr; // Chave de atributo
int my_attribute_value = 42; // Valor a ser associado
int *retrieved_attribute_ptr = NULL; // Ponteiro para armazenar o valor recuperado
int flag_get; // Flag para indicar se o atributo foi encontrado
int err;

// Duplica MPI_COMM_WORLD para criar um comunicador de teste (pode-se usar MPI_COMM_WORLD diretamente)
err = MPI_Comm_dup(MPI_COMM_WORLD, &comm_attr_test);

if (err == MPI_SUCCESS) {
    // Cria uma nova chave de atributo. Para MPI_Attr_put, esta chave é global.
    // MPI_Keyval_create cria a chave e associa as funções de cópia/exclusão. No MPI-1, as funções NULL eram permitidas.
    err = MPI_Keyval_create(MPI_NULL_COPY_FN, MPI_NULL_DELETE_FN, &keyval_attr, NULL);

    if (err == MPI_SUCCESS) {
        // Associa o valor do atributo (convertido para void*) ao comunicador usando a chave.
        // Se já houver um atributo com esta chave no comunicador, a função de exclusão será chamada.
        err = MPI_Attr_put(comm_attr_test, keyval_attr, &my_attribute_value);

        if (err == MPI_SUCCESS) {
            // Tenta recuperar o atributo para verificar se foi salvo corretamente.
            // MPI_Attr_get é a função correspondente para recuperar atributos definidos por MPI_Attr_put.
            err = MPI_Attr_get(comm_attr_test, keyval_attr, (void**)&retrieved_attribute_ptr, &flag_get);
            if (err == MPI_SUCCESS) {
                if (flag_get && retrieved_attribute_ptr != NULL) {
                    // Atributo recuperado com sucesso. O valor *retrieved_attribute_ptr deve ser 42.
                } else if (!flag_get) {
                    // Atributo não encontrado no comunicador.
                }
            } else {
                // Erro ao chamar MPI_Attr_get.
            }
        } else {
            // Erro ao chamar MPI_Attr_put.
        }

        // --- Limpeza --- 
        // Libera a chave de atributo criada.
        err = MPI_Keyval_free(&keyval_attr);
        if (err != MPI_SUCCESS) {
            // Lidar com erro na liberação da chave.
        }
    } else {
        // Erro ao chamar MPI_Keyval_create.
    }

    // Libera o comunicador duplicado.
    err = MPI_Comm_free(&comm_attr_test);
    if (err != MPI_SUCCESS) {
        // Lidar com erro na liberação do comunicador.
    }
} else {
    // Erro ao chamar MPI_Comm_dup.
}

