// Declarações
int rank_bsend;
int size_bsend;
int send_data = 567; // Dados a serem enviados
int recv_data; // Buffer para receber dados
int dest_rank = 1; // Processo de destino
int source_rank = 0; // Processo de origem
int tag_bsend = 100; // Etiqueta da mensagem
MPI_Comm comm_bsend = MPI_COMM_WORLD; // Comunicador
char *bsend_buffer = NULL; // Ponteiro para o buffer de envio fornecido pelo usuário
int bsend_buffer_size; // Tamanho do buffer de envio em bytes
MPI_Status status_bsend; // Status da operação de recepção
int err;

// Obtém o rank e o tamanho do comunicador
MPI_Comm_rank(comm_bsend, &rank_bsend);
MPI_Comm_size(comm_bsend, &size_bsend);

// Garante que há pelo menos 2 processos para comunicação bidirecional
if (size_bsend < 2) {
    return 1; // Retorna um código de erro simples
}

// --- Configuração do buffer para envios bufferizados (necessário para MPI_Bsend) ---
// Calcula o tamanho necessário para o buffer de Bsend.
// 1. Tamanho dos dados que serão enviados (1 inteiro).
// 2. Overhead adicional necessário para o MPI_Bsend, que o MPI usa para estruturas de controle.
int packed_size;
err = MPI_Pack_size(1, MPI_INT, comm_bsend, &packed_size);

if (err == MPI_SUCCESS) {
    bsend_buffer_size = packed_size + MPI_BSEND_OVERHEAD;

    // Aloca a memória para o buffer de envio fornecido pelo usuário
    bsend_buffer = (char *)malloc(bsend_buffer_size);

    if (bsend_buffer == NULL) {
        // Erro: falha na alocação de memória
        return 1;
    }

    // Anexa o buffer ao MPI. Agora, MPI_Bsend pode ser chamado usando este buffer.
    err = MPI_Buffer_attach(bsend_buffer, bsend_buffer_size);

    if (err == MPI_SUCCESS) {
        if (rank_bsend == source_rank) {
            // Processo de origem envia dados usando MPI_Bsend (envio bufferizado).
            // O MPI_Bsend copia os dados para o buffer interno e retorna imediatamente.
            // O envio real dos dados pela rede pode ocorrer em segundo plano.
            err = MPI_Bsend(&send_data, 1, MPI_INT, dest_rank, tag_bsend, comm_bsend);
            if (err == MPI_SUCCESS) {
                // Envio bufferizado iniciado com sucesso.
            } else {
                // Erro ao chamar MPI_Bsend.
            }
        } else if (rank_bsend == dest_rank) {
            // Processo de destino recebe os dados.
            // MPI_Recv bloqueará até que a mensagem correspondente seja recebida.
            err = MPI_Recv(&recv_data, 1, MPI_INT, source_rank, tag_bsend, comm_bsend, &status_bsend);
            if (err == MPI_SUCCESS) {
                // Dados recebidos com sucesso.
            } else {
                // Erro ao chamar MPI_Recv.
            }
        }

        // --- Limpeza: Desanexar e liberar o buffer ---
        // MPI_Buffer_detach bloqueará até que todas as mensagens bufferizadas pendentes
        // (enviadas via MPI_Bsend) tenham sido seguramente despachadas.
        int detached_size; // Variável para armazenar o tamanho do buffer desanexado
        void *detached_buffer_ptr; // Variável para armazenar o ponteiro para o buffer desanexado
        err = MPI_Buffer_detach(&detached_buffer_ptr, &detached_size);

        if (err == MPI_SUCCESS) {
            // O buffer foi desanexado. 'detached_buffer_ptr' aponta para o buffer original.
            if (detached_buffer_ptr != NULL) {
                free(detached_buffer_ptr); // Libera a memória alocada
                detached_buffer_ptr = NULL; // Evita uso de ponteiro inválido
            }
        } else {
            // Lidar com erro ao desanexar o buffer.
            // Se houve erro e o buffer não foi desanexado, ainda precisamos liberá-lo.
            if (bsend_buffer != NULL) {
                 free(bsend_buffer);
                 bsend_buffer = NULL;
            }
        }
    } else {
        // Erro ao chamar MPI_Buffer_attach. Libera o buffer alocado.
        if (bsend_buffer != NULL) {
            free(bsend_buffer);
            bsend_buffer = NULL;
        }
    }
} else {
    // Erro ao chamar MPI_Pack_size.
}

// Declarações
int rank_bsend_init;
