// Obtém o rank e o tamanho do comunicador
MPI_Comm_rank(comm_bsend_init, &rank_bsend_init);
MPI_Comm_size(comm_bsend_init, &size_bsend_init);

// Garante que há pelo menos 2 processos para comunicação
if (size_bsend_init < 2) {
    return 1;
}

// --- Configuração do buffer para envios bufferizados (necessário para MPI_Bsend_init) ---
// Calcula o tamanho necessário para o buffer
int packed_size_init;
err = MPI_Pack_size(1, MPI_INT, comm_bsend_init, &packed_size_init);

if (err == MPI_SUCCESS) {
    bsend_buffer_size_init = packed_size_init + MPI_BSEND_OVERHEAD;
    bsend_buffer_init = (char *)malloc(bsend_buffer_size_init);

    if (bsend_buffer_init == NULL) {
