    err = MPI_Buffer_attach(bsend_buffer_init, bsend_buffer_size_init);

    if (err == MPI_SUCCESS) {
        if (rank_bsend_init == source_rank_init) {
            // Inicializa uma requisição de envio bufferizado persistente.
            // Esta chamada apenas prepara a comunicação; o envio não começa ainda.
            err = MPI_Bsend_init(&send_data_init, 1, MPI_INT, dest_rank_init, tag_init, comm_bsend_init, &bsend_request);
            if (err == MPI_SUCCESS) {
                // Inicia a comunicação persistente. Os dados são copiados para o buffer interno do MPI.
                err = MPI_Start(&bsend_request);
                if (err == MPI_SUCCESS) {
                    // Espera pela conclusão da comunicação. Para MPI_Bsend, isso significa que
                    // os dados foram copiados para o buffer interno do MPI e a chamada é localmente completa.
                    err = MPI_Wait(&bsend_request, &status_bsend_init);
                    if (err == MPI_SUCCESS) {
                        // Envio persistente concluído com sucesso.
                    } else {
                        // Erro ao chamar MPI_Wait.
                    }
                } else {
                    // Erro ao chamar MPI_Start.
                }
            } else {
                // Erro ao chamar MPI_Bsend_init.
