        // --- Limpeza ---
        // Libera a requisição persistente criada por MPI_Bsend_init.
        // Deve ser chamada APÓS todas as operações MPI_Start/MPI_Wait associadas à requisição.
        if (rank_bsend_init == source_rank_init) {
            err = MPI_Request_free(&bsend_request);
            if (err != MPI_SUCCESS) {
                // Lidar com erro na liberação da requisição.
            }
        }

        // Desanexa e libera o buffer do Bsend.
        int detached_size_init;
        void *detached_buffer_ptr_init;
        err = MPI_Buffer_detach(&detached_buffer_ptr_init, &detached_size_init);

        if (err == MPI_SUCCESS) {
            if (detached_buffer_ptr_init != NULL) {
                free(detached_buffer_ptr_init);
                detached_buffer_ptr_init = NULL;
