            }
        }
    } else {
        // Erro ao chamar MPI_Buffer_attach. Libera o buffer alocado.
        if (bsend_buffer_init != NULL) {
            free(bsend_buffer_init);
            bsend_buffer_init = NULL;
        }
    }
} else {
    // Erro ao chamar MPI_Pack_size.
}

// Declarações
char *user_buffer = NULL; // Ponteiro para o buffer alocado pelo usuário
int buffer_size_bytes; // Tamanho do buffer em bytes
int packed_data_size; // Tamanho dos dados a serem embalados (para cálculo do buffer)
MPI_Comm comm_buffer_attach = MPI_COMM_WORLD; // Comunicador para MPI_Pack_size
void *detached_ptr = NULL; // Ponteiro para armazenar o endereço do buffer desanexado
int detached_size;         // Para armazenar o tamanho do buffer desanexado
int err;

// Determina o tamanho do buffer necessário para operações de envio bufferizadas.
// Por exemplo, se planejamos enviar 10 inteiros usando MPI_Bsend, precisamos calcular
// o espaço que eles ocupariam, mais o overhead do MPI.
int num_elements_to_send = 10; // Exemplo de quantidade de dados a serem enviados
err = MPI_Pack_size(num_elements_to_send, MPI_INT, comm_buffer_attach, &packed_data_size);

if (err == MPI_SUCCESS) {
    // O tamanho total do buffer deve incluir o overhead que o MPI pode usar para suas
    // estruturas de controle internas para cada mensagem Bsend.
    buffer_size_bytes = packed_data_size + MPI_BSEND_OVERHEAD; // Tamanho total necessário

    // Aloca a memória para o buffer que será fornecido pelo usuário ao MPI.
    user_buffer = (char *)malloc(buffer_size_bytes);

    if (user_buffer == NULL) {
        // Erro: falha na alocação de memória
        return 1;
    }

    // Anexa o buffer alocado pelo usuário ao MPI. Uma vez anexado, este buffer será
    // usado automaticamente por todas as chamadas subsequentes de MPI_Bsend.
    err = MPI_Buffer_attach(user_buffer, buffer_size_bytes);

    if (err == MPI_SUCCESS) {
        // O buffer foi anexado com sucesso.
        // A partir deste ponto, chamadas a MPI_Bsend utilizarão este buffer.
        // (Nenhuma chamada a MPI_Bsend é feita neste exemplo para focar apenas em attach/detach).

        // --- Limpeza: Desanexar e liberar o buffer ---
        // Mesmo que nenhum MPI_Bsend tenha sido feito, é importante mostrar o ciclo completo.
        // MPI_Buffer_detach bloqueia até que todas as mensagens pendentes tenham sido enviadas.
        err = MPI_Buffer_detach(&detached_ptr, &detached_size);

        if (err == MPI_SUCCESS) {
            // O buffer foi desanexado. `detached_ptr` apontará para `user_buffer`.
            if (detached_ptr != NULL) {
                free(detached_ptr); // Libera a memória alocada
                detached_ptr = NULL; // Evita uso de ponteiro inválido
            }
        } else {
            // Lidar com erro ao desanexar o buffer. Tentar liberar a memória alocada mesmo assim.
            if (user_buffer != NULL) {
                free(user_buffer);
                user_buffer = NULL;
            }
        }
    } else {
        // Erro ao anexar o buffer. Libera a memória alocada.
        if (user_buffer != NULL) {
            free(user_buffer);
            user_buffer = NULL;
        }
    }
} else {
    // Erro ao chamar MPI_Pack_size.
}

// Declarações
char *attached_user_buffer = NULL; // Ponteiro para o buffer anexado
int calculated_buffer_size; // Tamanho do buffer anexado
int packed_size_detach; // Tamanho dos dados a serem embalados
void *detached_buffer_addr = NULL; // Ponteiro para armazenar o endereço do buffer desanexado
int detached_buffer_size = 0; // Para armazenar o tamanho do buffer desanexado
int send_value = 999; // Valor a ser enviado via MPI_Bsend
int recv_value; // Valor a ser recebido via MPI_Recv
MPI_Request recv_request; // Requisição para MPI_Irecv no processo receptor
MPI_Status status_detach; // Status para operações de comunicação
int rank_detach;
int size_detach;
int dest_detach = 1; // Processo de destino
int source_detach = 0; // Processo de origem
int tag_detach = 300; // Etiqueta da mensagem
MPI_Comm comm_detach = MPI_COMM_WORLD; // Comunicador
int err;

// Obtém rank e size do comunicador
MPI_Comm_rank(comm_detach, &rank_detach);
MPI_Comm_size(comm_detach, &size_detach);

// Garante que há pelo menos 2 processos para comunicação bidirecional
if (size_detach < 2) {
    return 1;
}

// --- Parte 1: Anexar um buffer (necessário antes de detach) ---
// Calcula o tamanho necessário para o buffer para 1 inteiro + overhead
err = MPI_Pack_size(1, MPI_INT, comm_detach, &packed_size_detach);

if (err == MPI_SUCCESS) {
    calculated_buffer_size = packed_size_detach + MPI_BSEND_OVERHEAD;
    attached_user_buffer = (char *)malloc(calculated_buffer_size);

    if (attached_user_buffer == NULL) {
        // Erro na alocação de memória
        return 1;
    }

    err = MPI_Buffer_attach(attached_user_buffer, calculated_buffer_size);

    if (err == MPI_SUCCESS) {
        // --- Parte 2: Realizar um MPI_Bsend para ter algo no buffer ---
        if (rank_detach == source_detach) {
            // O processo de origem envia uma mensagem bufferizada.
            // Esta chamada retorna imediatamente, e a mensagem fica no buffer.
            err = MPI_Bsend(&send_value, 1, MPI_INT, dest_detach, tag_detach, comm_detach);
            if (err == MPI_SUCCESS) {
                // Envio bufferizado iniciado.
            } else {
                // Erro ao chamar MPI_Bsend.
            }
        } else if (rank_detach == dest_detach) {
            // O processo de destino inicia uma recepção não bloqueante
            // para que o envio bufferizado possa ser correspondido e concluído.
            err = MPI_Irecv(&recv_value, 1, MPI_INT, source_detach, tag_detach, comm_detach, &recv_request);
            if (err == MPI_SUCCESS) {
                // Recepção não bloqueante iniciada.
            } else {
                // Erro ao chamar MPI_Irecv.
            }
        }

        // --- Parte 3: Desanexar o buffer ---
        // MPI_Buffer_detach bloqueará até que o MPI_Bsend pendente no buffer tenha sido concluído
        // (ou seja, a mensagem foi entregue ou o MPI a moveu para seu próprio buffer interno).
        err = MPI_Buffer_detach(&detached_buffer_addr, &detached_buffer_size);

        if (err == MPI_SUCCESS) {
            // Verifica se o ponteiro e o tamanho retornados correspondem aos originais.
            if (detached_buffer_addr == attached_user_buffer && detached_buffer_size == calculated_buffer_size) {
                // Sucesso: Buffer desanexado e dados de retorno consistentes.
            } else {
                // Inconsistência nos dados de retorno do detach.
            }
            // Libera a memória alocada para o buffer, agora que foi desanexado e esvaziado.
            if (detached_buffer_addr != NULL) {
                free(detached_buffer_addr);
                detached_buffer_addr = NULL;
            }
        } else {
            // Lidar com erro ao desanexar o buffer.
            // Se houve erro e o buffer não foi desanexado, ainda precisamos liberar a memória original.
            if (attached_user_buffer != NULL) {
                free(attached_user_buffer);
                attached_user_buffer = NULL;
            }
        }

        // --- Limpeza adicional para o receptor ---
        if (rank_detach == dest_detach) {
            // Garante que a requisição de recepção não bloqueante é completada.
            err = MPI_Wait(&recv_request, &status_detach);
            if (err != MPI_SUCCESS) {
                // Lidar com erro no MPI_Wait.
            }
        }
    } else {
        // Erro ao chamar MPI_Buffer_attach. Libera o buffer alocado.
        if (attached_user_buffer != NULL) {
            free(attached_user_buffer);
            attached_user_buffer = NULL;
        }
    }
} else {
    // Erro ao chamar MPI_Pack_size.
}

// Declarações
int rank_cancel;
int size_cancel;
int source_cancel = 0; // Processo que pode enviar dados
int dest_cancel = 1;   // Processo que postará um Irecv e potencialmente o cancelará
int tag_cancel = 400; // Etiqueta da mensagem
MPI_Comm comm_cancel = MPI_COMM_WORLD; // Comunicador
int recv_buffer_cancel[10]; // Buffer para a recepção especulativa
MPI_Request irecv_request; // Requisição da operação de recepção não bloqueante
MPI_Status status_cancel; // Status da requisição após MPI_Wait
int cancelled_flag; // Flag para verificar se a requisição foi cancelada
