// Obtém rank e size do comunicador
MPI_Comm_rank(comm_cancel, &rank_cancel);
MPI_Comm_size(comm_cancel, &size_cancel);

// Garante que há pelo menos 2 processos para o exemplo
if (size_cancel < 2) {
    return 1;
}

if (rank_cancel == dest_cancel) {
