MPI_Comm comm_world_for_accept = MPI_COMM_WORLD; // Intracomunicador sobre o qual a chamada é coletiva
MPI_Comm newcomm_intercomm = MPI_COMM_NULL; // Intercomunicador resultante da conexão
int rank, size;
int err;

// Obter o rank e o tamanho para decidir quem será o root e participar do Bcast.
MPI_Comm_rank(MPI_COMM_WORLD, &rank);
MPI_Comm_size(MPI_COMM_WORLD, &size);

// O processo root abre a porta. Outros processos não precisam fazer isso.
if (rank == root) {
    err = MPI_Open_port(info, port_name_buffer);
    if (err != MPI_SUCCESS) {
        // Em caso de erro, invalidar o nome da porta para que os outros processos não tentem usar.
        port_name_buffer[0] = '\0'; 
        // fprintf(stderr, "Rank %d: Erro ao abrir a porta.\n", rank);
    } else {
        // fprintf(stderr, "Rank %d: Porta aberta: %s\n", rank, port_name_buffer);
        // Em um cenário real, o nome da porta seria comunicado a um processo cliente.
    }
}

// Transmitir o nome da porta para todos os processos no comunicador 'comm_world_for_accept'.
// Isso é necessário porque MPI_Comm_accept é uma chamada coletiva.
MPI_Bcast(port_name_buffer, MPI_MAX_PORT_NAME, MPI_CHAR, root, comm_world_for_accept);

// Verificar se a porta foi aberta com sucesso pelo root (ou se houve erro no Bcast).
if (port_name_buffer[0] != '\0') {
    // A chamada MPI_Comm_accept é coletiva em 'comm_world_for_accept'.
    // Ela aguarda uma conexão de um cliente na porta especificada.
    err = MPI_Comm_accept(port_name_buffer, info, root, comm_world_for_accept, &newcomm_intercomm);

    if (err == MPI_SUCCESS) {
        // Um novo intercomunicador (newcomm_intercomm) foi criado.
        // Ele conecta este grupo (o servidor) ao grupo do cliente.
        // fprintf(stderr, "Rank %d: Conexão aceita, novo intercomunicador criado.\n", rank);
        // O 'newcomm_intercomm' pode agora ser usado para comunicação com o cliente.
    } else {
        // fprintf(stderr, "Rank %d: Erro ao aceitar a conexão.\n", rank);
    }
} else {
    // fprintf(stderr, "Rank %d: Nenhuma porta válida para aceitar conexão.\n", rank);
}

// Limpeza: Se um novo intercomunicador foi criado, ele deve ser liberado.
if (newcomm_intercomm != MPI_COMM_NULL) {
    MPI_Comm_free(&newcomm_intercomm);
}

// Limpeza: O processo root fecha a porta que abriu.
if (rank == root && port_name_buffer[0] != '\0') {
    int close_err = MPI_Close_port(port_name_buffer);
    if (close_err != MPI_SUCCESS) {
        // fprintf(stderr, "Rank %d: Erro ao fechar a porta.\n", rank);
    }
}

