MPI_Comm_get_errhandler(comm, &old_errhandler);

// Definir o manipulador de erros para MPI_ERRORS_RETURN.
err = MPI_Comm_set_errhandler(comm, MPI_ERRORS_RETURN);

if (err == MPI_SUCCESS) {
    // Invocar manualmente o manipulador de erros associado ao comunicador.
    // Com MPI_ERRORS_RETURN, esta chamada retornará 'errorcode' (MPI_ERR_OTHER neste caso).
    err = MPI_Comm_call_errhandler(comm, errorcode);

    if (err != MPI_SUCCESS) {
        // fprintf(stderr, "Rank %d: O manipulador de erros foi invocado com código %d, e retornou %d (esperado %d).\n", 
        //          rank, errorcode, err, errorcode);
    } else {
