        // fprintf(stderr, "Rank %d: Erro inesperado: MPI_Comm_call_errhandler retornou MPI_SUCCESS com código %d.\n", rank, errorcode);
    }
} else {
    // fprintf(stderr, "Rank %d: Erro ao definir o manipulador de erros.\n", rank);
}

// Limpeza: Restaurar o manipulador de erros original.
// MPI_ERRORS_RETURN não precisa de MPI_Errhandler_free, mas old_errhandler pode precisar
// se fosse um customizado criado com MPI_Comm_create_errhandler. 
// Como salvamos um handler pré-definido (como MPI_ERRORS_ARE_FATAL), não o liberamos.
