// Declarações
MPI_Comm comm1 = MPI_COMM_WORLD;
MPI_Comm comm2 = MPI_COMM_WORLD;
MPI_Comm duplicated_comm = MPI_COMM_NULL; // Para demonstração de comparação com um comunicador diferente
int result;
int err;

// Duplica MPI_COMM_WORLD para ter um comunicador idêntico mas com contexto diferente
// Esta é uma operação coletiva, todos os processos devem chamá-la.
err = MPI_Comm_dup(MPI_COMM_WORLD, &duplicated_comm);

if (err == MPI_SUCCESS) {
    // Compara MPI_COMM_WORLD com ele mesmo. Espera-se MPI_IDENT (referem-se ao mesmo objeto).
    err = MPI_Comm_compare(comm1, comm2, &result);

    if (err == MPI_SUCCESS) {
        // if (result == MPI_IDENT) { /* Comunicadores são idênticos */ }

        // Agora compara MPI_COMM_WORLD com a sua duplicata.
        // Espera-se MPI_CONGRUENT (mesmo grupo, mas contexto de comunicação diferente).
        err = MPI_Comm_compare(comm1, duplicated_comm, &result);
        if (err == MPI_SUCCESS) {
            // if (result == MPI_CONGRUENT) { /* Comunicadores são congruentes */ }
            // Sucesso na comparação.
        }
    }
} else {
    // Erro ao duplicar o comunicador.
}

