// Cria um objeto MPI_Info (pode ser usado para passar dicas, como segurança ou desempenho)
err = MPI_Info_create(&info);

if (err == MPI_SUCCESS) {
    // Opcional: Define algumas dicas para a conexão.
    // err = MPI_Info_set(info, "security_level", "high");

    // Somente um cliente (e.g., rank 0) tenta conectar.
    // Em um cenário real, o cliente e o servidor seriam processos diferentes e a conexão
    // seria estabelecida através de MPI_Comm_connect no cliente e MPI_Comm_accept no servidor.
    if (rank == 0) {
        // Tenta conectar ao servidor que supostamente estaria "escutando" no 'port_name'.
        // 'root_server' é o rank do servidor dentro do comunicador 'client_comm' (se eles compartilhassem um).
        // Em um modelo de cliente/servidor separado, 'root_server' se refere ao rank do servidor no intercomunicador.
        err = MPI_Comm_connect(port_name, info, root_server, client_comm, &newcomm);

        if (err == MPI_SUCCESS) {
            // Sucesso na conexão. 'newcomm' agora é um intercomunicador.
            // Pode-se usar 'newcomm' para comunicação com o servidor.
            // Exemplo: int message = 123; MPI_Send(&message, 1, MPI_INT, 0, 0, newcomm);
        } else {
            // Erro na conexão.
        }
    }
} else {
