    MPI_Comm target_comm = MPI_COMM_WORLD; // Comunicador para associar o handler
    MPI_Errhandler old_errhandler = MPI_ERRHANDLER_NULL; // Para guardar o handler original

    // Opcional: Salvar o manipulador de erros atual do comunicador para restaurar depois.
    err = MPI_Comm_get_errhandler(target_comm, &old_errhandler);

    if (err == MPI_SUCCESS) {
        // 2. Associa o novo manipulador de erros ao comunicador.
        err = MPI_Comm_set_errhandler(target_comm, errhandler);

        if (err == MPI_SUCCESS) {
            // O MPI_COMM_WORLD agora usará 'errhandler' para tratar erros.
