        }
    }

    // 3. Opcional: Restaurar o manipulador de erros original para o comunicador.
    if (old_errhandler != MPI_ERRHANDLER_NULL) {
        MPI_Comm_set_errhandler(target_comm, old_errhandler);
        // Não precisamos liberar old_errhandler se for um dos handlers predefinidos (MPI_ERRORS_ARE_FATAL, etc.).
