// Declarações
// Ponteiros para as funções de callback.
// MPI_Comm_copy_attr_function e MPI_Comm_delete_attr_function são typedefs para ponteiros de função.
MPI_Comm_copy_attr_function *comm_copy_attr_fn_ptr;
MPI_Comm_delete_attr_function *comm_delete_attr_fn_ptr;
int comm_keyval = MPI_KEYVAL_INVALID; // Inicializa com valor inválido para a chave do atributo
int my_extra_state_data = 123;      // Exemplo de dado para o parâmetro 'extra_state'
void *extra_state = &my_extra_state_data;
int err;

// --- Definições das Funções de Callback para o Atributo ---

// Função de cópia de atributo: Chamada quando um comunicador com este atributo é duplicado.
// Retorna MPI_SUCCESS se o atributo deve ser copiado, ou um código de erro caso contrário.
int my_copy_attr_function(MPI_Comm oldcomm, int keyval, void *extra_state, void *attribute_val_in, void *attribute_val_out, int *flag) {
    // printf("my_copy_attr_function chamada!\n");
    // Se o atributo existe no comunicador antigo (*attribute_val_in é não-NULL)
    if (attribute_val_in != NULL) {
        // Copia o valor do atributo (assumindo que é um int para este exemplo)
        *((int*)attribute_val_out) = *((int*)attribute_val_in);
        *flag = 1; // Indica que o atributo deve ser copiado para o novo comunicador
    } else {
        *flag = 0; // Indica que o atributo não deve ser copiado
    }
    return MPI_SUCCESS;
}

// Função de exclusão de atributo: Chamada quando um atributo é removido
// ou o comunicador ao qual está associado é liberado.
// Retorna MPI_SUCCESS ou um código de erro.
int my_delete_attr_function(MPI_Comm comm, int keyval, void *attribute_val, void *extra_state) {
    // printf("my_delete_attr_function chamada! Valor do atributo: %d\n", (attribute_val != NULL ? *(int*)attribute_val : -1));
    // Aqui você liberaria qualquer memória alocada dinamicamente para 'attribute_val'.
    // Para este exemplo, o valor é um inteiro simples (stack-allocated), então não há alocação dinâmica para liberar.
    return MPI_SUCCESS;
}

// Atribui as funções personalizadas aos ponteiros de função.
comm_copy_attr_fn_ptr = &my_copy_attr_function;
comm_delete_attr_fn_ptr = &my_delete_attr_function;

// 1. Cria uma nova chave de atributo que pode ser usada com comunicadores.
err = MPI_Comm_create_keyval(comm_copy_attr_fn_ptr, comm_delete_attr_fn_ptr, &comm_keyval, extra_state);

if (err == MPI_SUCCESS) {
    // Sucesso na criação da chave. Agora podemos usar 'comm_keyval' para armazenar e recuperar dados.

    // Exemplo: Armazenar um atributo em MPI_COMM_WORLD
    MPI_Comm comm_to_set_attr = MPI_COMM_WORLD;
    int attribute_value = 42;
    void *attr_data_ptr = &attribute_value; // Ponteiro para o dado do atributo

    // 2. Define o atributo no comunicador usando a chave criada.
    err = MPI_Comm_set_attr(comm_to_set_attr, comm_keyval, attr_data_ptr);

    if (err == MPI_SUCCESS) {
        // Atributo definido. Agora vamos tentar recuperá-lo.
        void *retrieved_attr_ptr;
        int flag_found; // Indica se o atributo foi encontrado

        // 3. Recupera o atributo do comunicador.
        err = MPI_Comm_get_attr(comm_to_set_attr, comm_keyval, &retrieved_attr_ptr, &flag_found);

        if (err == MPI_SUCCESS && flag_found) {
            // int retrieved_value = *(int*)retrieved_attr_ptr; // Deve ser 42
            // printf("Atributo recuperado com sucesso: %d\n", retrieved_value);
        } else {
            // Erro ao recuperar o atributo ou atributo não encontrado.
        }

        // Exemplo de duplicação de comunicador para testar a função de cópia (my_copy_attr_function).
        MPI_Comm duplicated_comm = MPI_COMM_NULL;
        err = MPI_Comm_dup(comm_to_set_attr, &duplicated_comm);
        if (err == MPI_SUCCESS) {
