// Função de callback para o manipulador de erros personalizado.
// Esta função será invocada se um erro ocorrer no comunicador ao qual está associada.
void my_err_handler_fn(MPI_Comm *comm_p, int *error_code, ...) {
    // Em uma implementação real, você faria algo útil aqui,
    // como imprimir informações do erro, logar, ou talvez abortar o programa.
    // printf("[%d] Erro detectado (custom handler)! Código: %d\n", *comm_p, *error_code);
    // MPI_Abort(*comm_p, *error_code); // Exemplo de ação.
}

// 1. Cria um manipulador de erros personalizado a partir da função de callback.
