if (err == MPI_SUCCESS) {
    // 2. Opcional: Salva o manipulador de erros atual do comunicador para restaurá-lo depois.
    MPI_Comm_get_errhandler(comm, &old_errhandler);

    // 3. Define o manipulador de erros personalizado para o comunicador MPI_COMM_WORLD.
    err = MPI_Comm_set_errhandler(comm, custom_errhandler);

    if (err == MPI_SUCCESS) {
        // 4. Recupera o manipulador de erros atualmente associado ao comunicador.
        err = MPI_Comm_get_errhandler(comm, &current_errhandler);

        if (err == MPI_SUCCESS) {
            // 'current_errhandler' agora contém o handle para o manipulador de erros ativo.
            // Em um sistema real, você poderia comparar 'current_errhandler' com 'custom_errhandler'
            // para verificar se o manipulador personalizado está ativo.
        }

        // 5. Limpa: Restaura o manipulador de erros original do comunicador.
        MPI_Comm_set_errhandler(comm, old_errhandler);

    }

    // 6. Limpa: Libera o manipulador de erros personalizado criado.
    int cleanup_err = MPI_Errhandler_free(&custom_errhandler);
    if (cleanup_err == MPI_SUCCESS) {
