MPI_Comm comm = MPI_COMM_WORLD;
MPI_Comm newcomm;     // Novo comunicador que será criado de forma assíncrona
MPI_Request request;  // Requisição para a operação de duplicação assíncrona
MPI_Status status;    // Status da operação assíncrona após a conclusão

// Inicia a duplicação assíncrona do comunicador 'comm'.
// O handle para o novo comunicador ('newcomm') será válido somente após a conclusão da requisição.
int err = MPI_Comm_idup(comm, &newcomm, &request);

if (err == MPI_SUCCESS) {
    // Neste ponto, a duplicação está em andamento no background.
    // Outras operações não bloqueantes poderiam ser realizadas aqui.

    // Espera pela conclusão da duplicação do comunicador.
    // MPI_Wait é uma chamada bloqueante que aguarda até que a requisição seja completada.
    err = MPI_Wait(&request, &status);

    if (err == MPI_SUCCESS) {
        // A duplicação foi concluída com sucesso.
        // 'newcomm' agora é um comunicador válido, idêntico a 'comm' em termos de grupo e contexto.
        // Exemplo de uso: int rank; MPI_Comm_rank(newcomm, &rank);
        // printf("Duplicação assíncrona concluída. Newcomm está pronto.\n");

        // Limpa: Libera o novo comunicador criado.
        int cleanup_err_comm = MPI_Comm_free(&newcomm);
        if (cleanup_err_comm == MPI_SUCCESS) {
            newcomm = MPI_COMM_NULL;
        }

        // A requisição é automaticamente invalidada por MPI_Wait, mas é uma boa prática
        // definir o handle para MPI_REQUEST_NULL para evitar uso indevido.
        request = MPI_REQUEST_NULL;

    }
} else {
    // Erro ao iniciar a duplicação assíncrona do comunicador.
}

