    // Define o novo manipulador de erros para MPI_ERRORS_RETURN.
    // Após esta chamada, se uma função MPI falhar no 'comm_err', ela retornará um código
    // de erro (diferente de MPI_SUCCESS) e o programa continuará sua execução,
    // permitindo tratamento de erros programático.
    int err_set_handler = MPI_Comm_set_errhandler(comm_err, MPI_ERRORS_RETURN);

    if (err_set_handler == MPI_SUCCESS) {
        // O manipulador de erros foi definido com sucesso.
        // Agora, qualquer erro em operações MPI usando 'comm_err' retornará um código de erro.

        // Limpeza: Restaura o manipulador de erros original para o comunicador.
        // Isso é importante para garantir que o comportamento de tratamento de erros seja
        // revertido ao estado anterior, evitando efeitos colaterais em outras partes do código.
        MPI_Comm_set_errhandler(comm_err, old_errhandler);
        // Se 'old_errhandler' tivesse sido criado com MPI_Errhandler_create,
        // ele precisaria ser liberado com MPI_Errhandler_free(&old_errhandler).
        // Como estamos lidando com um handle possivelmente predefinido, não o liberamos aqui.
