// Variáveis para a operação de Comparação e Troca Atômica (CAS)
int *local_data_window = NULL; // Ponteiro para a memória da janela no processo alvo
int origin_val = rank + 100;     // Valor que o processo 'origin' tenta escrever
int compare_val;                 // Valor para comparação
int result_val;                  // Valor lido do alvo ANTES da operação CAS

MPI_Datatype datatype = MPI_INT;
int target_rank = 0;              // O processo 0 será o alvo da operação CAS
MPI_Aint target_disp = 0;         // Deslocamento dentro da janela do alvo (neste caso, 0)
MPI_Win win = MPI_WIN_NULL;       // Objeto de janela RMA

// O processo alvo (target_rank) aloca memória e cria a janela
if (rank == target_rank) {
    // Alocar memória alinhada para RMA
    MPI_Alloc_mem(sizeof(int), MPI_INFO_NULL, &local_data_window);
    *local_data_window = 50; // Valor inicial na janela do processo alvo
    // printf("Processo %d (alvo): Valor inicial na janela = %d\n", rank, *local_data_window);
} else {
    // Outros processos não alocam memória para si, apenas a acessam remotamente
    local_data_window = NULL;
}

// Criar o objeto de janela em todos os processos. O processo alvo fornece o buffer, outros NULL.
MPI_Win_create(local_data_window, (rank == target_rank ? sizeof(int) : 0), sizeof(int), MPI_INFO_NULL, comm, &win);

// Sincronização: todos os processos iniciam um fence para abrir acesso à janela
// MPI_Win_fence é uma forma de sincronização coletiva. Alternativas são Active Target.
MPI_Win_fence(0, win);

if (rank != target_rank) {
    // Outros processos (diferentes do alvo) tentam realizar a operação CAS
    // Definir o valor para comparação.
    // Vamos tentar comparar com o valor inicial esperado (50) e, se igual, trocar para origin_val.
    compare_val = 50;

    // Chamada da função MPI_Compare_and_swap
    // origin_addr: valor que será escrito no alvo se a comparação for bem-sucedida
    // compare_addr: valor com o qual o valor atual do alvo será comparado
    // result_addr: onde o valor ANTERIOR do alvo será armazenado
    err = MPI_Compare_and_swap(&origin_val, &compare_val, &result_val, datatype, target_rank, target_disp, win);

    if (err == MPI_SUCCESS) {
        // printf("Processo %d: CAS bem-sucedido. Valor lido antes da troca: %d. Tentou comparar com %d e trocar por %d.\n", rank, result_val, compare_val, origin_val);
    } else {
        // printf("Processo %d: Erro na operação CAS: %d\n", rank, err);
    }
}

// Sincronização: todos os processos fecham o fence para garantir que as operações RMA foram concluídas
MPI_Win_fence(0, win);

