// Declarações
int rank_exscan; // Rank do processo
int size_exscan; // Número total de processos
int send_value; // Valor que cada processo envia para a operação Exscan
int recv_value = 0; // Valor recebido por cada processo (resultado da Exscan), inicializado
int count = 1; // Número de elementos
MPI_Datatype datatype = MPI_INT; // Tipo de dados
MPI_Op op = MPI_SUM; // Operação de redução (soma)
MPI_Comm comm_exscan = MPI_COMM_WORLD; // Comunicador
int err; // Variável para armazenar o retorno das funções MPI

// Obtém o rank e o tamanho do comunicador para usar no exemplo
err = MPI_Comm_rank(comm_exscan, &rank_exscan);
if (err != MPI_SUCCESS) { /* tratamento de erro */ }
err = MPI_Comm_size(comm_exscan, &size_exscan);
if (err != MPI_SUCCESS) { /* tratamento de erro */ }

// Cada processo envia seu rank como valor.
send_value = rank_exscan;

// Realiza a operação MPI_Exscan.
// O processo 'i' recebe a redução de todos os processos de 0 até 'i-1'.
// O buffer de recebimento do processo 0 não é alterado e mantém o valor inicial.
err = MPI_Exscan(&send_value, &recv_value, count, datatype, op, comm_exscan);

if (err == MPI_SUCCESS) {
    // Exemplos de resultados com send_value = rank_exscan:
    // Se rank = 0: recv_value permanece 0 (valor inicial, não é modificado por Exscan)
    // Se rank = 1: recv_value = 0 (soma do rank 0)
    // Se rank = 2: recv_value = 0 + 1 = 1 (soma dos ranks 0 e 1)
    // Se rank = 3: recv_value = 0 + 1 + 2 = 3 (soma dos ranks 0, 1 e 2)
    // e assim por diante.
}

// Declarações
int rank_fop, size_fop; // Rank e tamanho do processo
int *shared_data_local_ptr = NULL; // Ponteiro para a memória local que será exposta na janela
MPI_Win win_fop = MPI_WIN_NULL; // Objeto de janela MPI
int origin_value = 5; // Valor a ser combinado com o alvo
int fetched_old_value = 0; // Valor original no alvo antes da operação (inicializado)
MPI_Datatype datatype_fop = MPI_INT; // Tipo de dados
int target_rank = 0; // Rank do processo alvo (o que possui a janela)
MPI_Aint target_disp = 0; // Deslocamento no alvo (primeiro elemento do array)
MPI_Op op_fop = MPI_SUM; // Operação (soma atômica)
int err; // Variável para armazenar o retorno das funções MPI

// Obtém o rank e o tamanho do comunicador
err = MPI_Comm_rank(MPI_COMM_WORLD, &rank_fop);
if (err != MPI_SUCCESS) { /* tratamento de erro */ }
err = MPI_Comm_size(MPI_COMM_WORLD, &size_fop);
if (err != MPI_SUCCESS) { /* tratamento de erro */ }

// Apenas o rank alvo (target_rank) aloca a memória que será acessada por RMA.
MPI_Aint winsize = 0;
int disp_unit = sizeof(int);

if (rank_fop == target_rank) {
    winsize = sizeof(int);
    // Aloca a memória que será exposta pelo rank alvo (baseptr para MPI_Win_create)
    shared_data_local_ptr = (int*) malloc(winsize);
    if (shared_data_local_ptr == NULL) {
        // Erro de alocação de memória. Em um cenário real, você abortaria ou trataria.
        // MPI_Abort(MPI_COMM_WORLD, 1);
    }
    *shared_data_local_ptr = 100; // Valor inicial no alvo
}

// Cria um objeto de janela MPI para acesso RMA (One-Sided Communication)
err = MPI_Win_create(shared_data_local_ptr, winsize, disp_unit, MPI_INFO_NULL, MPI_COMM_WORLD, &win_fop);

if (err == MPI_SUCCESS) {
    // Sincronização de janela (MPI_Win_fence é um modelo de sincronização)
    // Garante que todos os processos estabeleceram a janela e a memória está pronta para acesso.
    err = MPI_Win_fence(0, win_fop);
    if (err != MPI_SUCCESS) { /* tratamento de erro */ }

    if (rank_fop != target_rank) { // Processos diferentes do alvo (originadores)
        // Realiza uma operação atômica de fetch-and-op.
        // O valor atual do alvo (em shared_data_local_ptr no target_rank) é retornado em 'fetched_old_value'.
        // Em seguida, 'origin_value' é somado atomicamente ao valor no alvo.
        err = MPI_Fetch_and_op(&origin_value, &fetched_old_value, datatype_fop, target_rank, target_disp, op_fop, win_fop);
        if (err == MPI_SUCCESS) {
            // fetched_old_value conteria 100 para a primeira operação do originador.
            // O valor no alvo seria 100 + origin_value.
        }
    }

    // Sincronização novamente para garantir que todas as operações RMA estejam completas
    err = MPI_Win_fence(0, win_fop);
    if (err != MPI_SUCCESS) { /* tratamento de erro */ }

    if (rank_fop == target_rank) {
        // O rank alvo pode verificar o valor final no shared_data_local_ptr.
        // Se houver N-1 originadores, o valor final seria 100 + (N-1) * origin_value.
    }

    // Libera o objeto de janela MPI
    err = MPI_Win_free(&win_fop);
    if (err != MPI_SUCCESS) { /* tratamento de erro */ }
}

// Libera a memória alocada localmente pelo rank alvo, se foi alocada.
if (rank_fop == target_rank && shared_data_local_ptr != NULL) {
    free(shared_data_local_ptr);
}

