void soma_quadrados(void *invec, void *inoutvec, int *len, MPI_Datatype *datatype) {
    int *in = (int *)invec;
    int *inout = (int *)inoutvec;
    int n = *len;
    for (int i = 0; i < n; i++) {
        inout[i] += in[i] * in[i];
    }
}
